mapper.select:
select o2.id
from orders o2

    o2.user_id = #{userId}
    and o2.is_delete = 1

        and o2.status in

            #{s}



        and o2.order_no like concat('%', #{dto.orderNo}, '%')


order by o2.created_time desc

    , o2.actual_amount ${dto.amountSort}

limit #{limit} offset #{offset}

select o2.id
from orders o2

    o2.business_id = #{businessId}
    and o2.is_delete = 1

        and o2.status in

            #{s}



        and o2.created_time >= #{dto.startTime}


        and o2.created_time <= #{dto.endTime}


        and o2.order_no like concat('%', #{dto.orderNo}, '%')


order by o2.created_time desc

    , o2.actual_amount ${dto.amountSort}

limit #{limit} offset #{offset}

select oc.id, oc.order_id, oc.order_no, o.actual_amount, oc.reason_type, oc.reason, oc.status, o.status order_status, oc.created_time from order_cancel oc left join orders o on o.id = oc.order_id
o.business_id = #{businessId}
and o.status = #{status}
order by oc.created_time desc
